// === The 97-tick / 24-frame presentation schedule (V2 correction pass) ======
// Each frame's HOLD is the approved Stage 8C-4 V2 frame/phase contract (sums to 97,
// +18.3% over v1's 82 — the "slightly slower, more readable" pacing, C1). The extra
// ticks land ONLY on anticipation / launch / apex / plunge / impact-holds / the S5
// pillar event / the teleport return — the travel frames keep their 2 ticks so the
// combo still spends its time MOVING, not posing (see hero_combo_a_v2_spec.md §C1).
// [frameIndex, holdTicks, tag]. The controller runs its OWN step->state clock
// (handoff risk 6: never phase-index Combo A off COMBO.HITS).
const STEPS = [
    { clip: 'heroComboA1', frames: [[0, 5, 'W1'], [1, 2, 'A1A'], [2, 5, 'A1B'], [3, 4, 'L1']] },                                 // 16
    { clip: 'heroComboA2', frames: [[0, 5, 'W2'], [1, 3, 'J2'], [2, 6, 'T2'], [3, 3, 'D2A'], [4, 6, 'D2B'], [5, 4, 'R2']] },      // 27
    { clip: 'heroComboA3', frames: [[0, 4, 'W3'], [1, 2, 'A3A'], [2, 5, 'A3B'], [3, 3, 'L3']] },                                 // 14
    { clip: 'heroComboA4', frames: [[0, 4, 'W4'], [1, 2, 'A4A'], [2, 4, 'A4B'], [3, 2, 'L4']] },                                 // 12
    { clip: 'heroComboA5', frames: [[0, 4, 'P5A'], [1, 6, 'P5B'], [2, 5, 'P5C'], [3, 4, 'E5A'], [4, 4, 'E5B'], [5, 5, 'E5C']] }, // 28
];

// Flatten to a per-tick lookup so draw is deterministic and the held frames never
// drift. TICK_MAP[t] = { step, clip, frame, tag, first } for t in [0, 97).
const TICK_MAP = (() => {
    const out = [];
    STEPS.forEach((s, si) => {
        for (const [frame, hold, tag] of s.frames) {
            for (let k = 0; k < hold; k++) {
                out.push({ step: si, clip: s.clip, frame, tag, first: k === 0 });
            }
        }
    });
    return out;
})();
const TOTAL_TICKS = TICK_MAP.length; // 97

// === STAGE 8C-4 FOLLOW-UP — Combo-A-local playback rate ====================
// The whole MERIDIAN sequence plays at HALF speed: the schedule above is unchanged
// (same 97 ticks, same frames, same relative proportions), but the controller's own
// clock advances by this much per game frame, so the combo occupies 97 / 0.5 = 194
// game frames end-to-end. Everything Combo A owns and that is measured in GAME
// FRAMES rather than combo ticks (the per-frame chase velocity, the airborne arc
// parameter, the strike active windows, the glaive's speed + lifetime) is divided /
// multiplied by this same scale below, so movement, effects and the animation stay
// locked together and nothing finishes early and waits. Strictly local: no global
// game-speed multiplier, no shared timing constant touched, so every other Hero
// attack (Daybreak, Dragon Wrath, Combo B) keeps its original speed.
const COMBO_A_TIME_SCALE = 0.5;

// === The loop clock (asserted by the V2 handoff — hero_combo_a_v2_spec.md) ==
// C3: the single Noon Pillar is now a FORWARD SEQUENTIAL CHAIN — 7 frames (PC0..PC6),
// four stations, one station erupting per beat and dissolving in the same forward
// order. Beats fall every 4 ticks (PC0 69 · PC1 73 · PC2 77 · PC3 81 · PC4 85 · PC5
// 89 · PC6 93), the chain dies at the end of PC6 (tick 97). The ECHO RETURN lands at
// tick 88 (E5B) during PC4 — inside the still-lit corridor bed — and the far station
// opens its grand crown at PC5 (89), AFTER the hero is already home. Margin = 9 ticks
// (identical to v1's margin — the identity is preserved).
const PILLAR_START = 69;              // P5A SEED / PC0 — S5 begins (S1..S4 = 16+27+14+12)
const PILLAR_CLOCK = [4, 4, 4, 4, 4, 4, 4]; // PC0..PC6, one station-beat every 4 ticks (dies tick 97)
const CORRIDOR_START = 57;           // CR0 cut, carved from W4/A4A — the bed the return lands in
const CORRIDOR_LIT_END = 89;         // CR1 lit-bed [69,89) -> CR2 residue [89,97); the return (88) lands in CR1
const REFORM_START = 84;             // E5A UNMAKE — the arrival cover begins at the mark
const DEPART_TICK = 84;              // E5A — Hero dissolves at the far end
const ARRIVE_TICK = 88;              // E5B — Hero reforms AT THE MARK (before the chain dies 97)

// === Combo-A-local gameplay values (scoped here; reported in the handoff) ===
// Forward advance: handoff ADVANCE_PX = 150 sheet-px = 5 hero lengths; in-game the
// hero renders at 2px/cell, so 150 * 2 = 300 world-px. Distributed over the 7 chase
// ticks. main.js clampToWorld() is the in-bounds backstop at either wall.
const ADVANCE_PX = 300;
const ADVANCE_TAGS = { A4A: true, A4B: true, L4: true };
const ADVANCE_TICKS = 8;             // V2 holds: A4A(2) + A4B(4) + L4(2)
const ADVANCE_PER_TICK = ADVANCE_PX / ADVANCE_TICKS;

// The dive arc (C2 — DIAGONAL plunge). Local vertical + forward override for S2 ONLY;
// restored on land / cleanup so global jump physics are never touched. 12 airborne
// ticks under V2 holds: J2(3)+T2(6)+D2A(3). The launch is vertical; the DESCENDING
// half carries a fixed forward drift so the hero cuts DOWN-AND-FORWARD on a clear
// diagonal and lands ahead of the launch point (hero_combo_a_v2_spec.md §C2).
const APEX_H = 130;                  // launch height (px) — comparable to the JUMP arc
const DIVE_FORWARD_PX = 90;          // forward displacement over the descent — clearly diagonal, not a dash
const AIRBORNE_TAGS = { J2: true, T2: true, D2A: true };
const AIRBORNE_TICKS = 12;

// Strike windows drive the SHARED attackHitbox (existing convention, Hero's own
// attackDamage stat — no global damage/balance change). dmgMult mirrors the melee
// combo's own range (0.8-1.5). Armed on the first tick of the strike frame.
const STRIKES = {
    A1B: { reachOff: 24, width: 44, height: 46, dmgMult: 0.9, knockback: 7, active: 4 },  // S1 opener HIT
    D2B: { reachOff: 22, width: 52, height: 48, dmgMult: 1.3, knockback: 15, active: 5 }, // S2 dive SLAM
    A4B: { reachOff: 30, width: 48, height: 46, dmgMult: 1.0, knockback: 10, active: 3 }, // S4 CHASE CUT
};

// The thrown slash projectile (S3). A Combo-A-owned Hitbox on the existing
// projectiles[] seam (surfaced via getActiveHitboxes, so main.js damages the Boss
// with it exactly like a light-wave). kind 'comboAGlaive' keeps drawWaveProjectiles
// from double-drawing it (that path only renders kind === 'wave'); this module
// paints it as the approved lightGlaive grid instead.
const GLAIVE = {
    WIDTH: 40, HEIGHT: 40, SPEED: 8.0, LIFETIME: 60,
    DMG_MULT: 0.6, KNOCKBACK: 5, SPAWN_OFF: 14, SPAWN_RISE: 8, KIND: 'comboAGlaive',
};

// Detached-grid local anchors (cells) from the handoff §4/§6.
// V2/C3: the pillar grid is now the 100-wide FORWARD CHAIN. Its NEAR station sits at
// col 12; we anchor THAT station on the old far-end spot and let the chain march
// FORWARD from there (stations at cols 12/36/60/84). Unlike v1's single h-symmetric
// pillar, the chain is DIRECTIONAL, so it mirrors with facing (see drawWorldEffects).
const G_PILLAR = { cx: 12, baseRow: 68 };  // NEAR station col 12, floor/base row 68
const PILLAR_COLS = 100;                   // chain grid width (cells) — for the arena clamp
const G_REFORM = { cx: 16, cy: 16 };       // centre (16,16)
const G_GLAIVE = { cx: 11, cy: 12 };       // centre (11,12)
const G_CORRIDOR = { cx: 5, row: 8 };      // mark node col 5, centre row 8
// The return bed (corridor cut line + reform halo) sits at the reforming body's
// torso — a little above the collision centre.
const RETURN_BED_DY = 8;

function frameFromClock(local, clock) {
    if (local < 0) return -1;
    let acc = 0;
    for (let i = 0; i < clock.length; i++) { acc += clock[i]; if (local < acc) return i; }
    return -1;
}

// ---------------------------------------------------------------------------
// The controller. One instance per Enemy (host). All state is namespaced here so
// nothing leaks into the other Hero attacks. Cleanup is idempotent.
// ---------------------------------------------------------------------------
export class HeroComboA {
    constructor(host) {
        this.host = host;
        this._reset();
    }

    _reset() {
        this.active = false;
        this.clock = 0;       // FRACTIONAL combo clock — advances COMBO_A_TIME_SCALE per game frame
        this._lastTick = -1;  // last INTEGER combo tick entered (so per-frame enters fire exactly once)
        this.tag = null;
        this.frameName = 'heroComboA1';
        this.frameIndex = 0;
        this.drawTick = 0;    // the tick last processed (what the body frame + effects show)
        this.facingLock = 1;
        // STAGE 8C-4 FOLLOW-UP — per-phase direction. facingLock stays the ONE thing
        // the body / strikes / advance read, but it is re-pointed at exactly two
        // transitions (chase start W4, pillar start P5A) if the Boss has crossed to the
        // Hero's other side. These three keep each phase's already-drawn world effects
        // from mirroring underneath a later flip.
        this.startDir = 1;    // S1..S3 direction — the glaive's baked travel/draw side
        this.chaseDir = 1;    // S4 direction — the chase cut + the corridor bed
        this.pillarDir = 1;   // S5 direction — which way the pillar chain marches
        this._bossX = null;   // Boss centre x, refreshed each update() by Enemy
        // captured anchors
        this.floorY = 0;      // world Y of the floor surface (feet line)
        this.markX = 0;       // THE MARK — the stored step-4 return position
        this.markY = 0;
        this.farEndX = 0;     // the pillar / chase destination
        this.pillarAnchorX = 0; // C3: near-station world x for the chain (arena-clamped at seed)
        // C2 diagonal-plunge trajectory (established cleanly at launch; never re-homes)
        this._diveLaunchX = 0;
        this._diveTargetX = 0;
        // per-run ownership / status
        this._airTick = 0;
        this._teleported = false;
        this._glaiveSpawned = false;
        this._gravityOverridden = false;
        this._savedGravity = 0;
    }

    get isActive() { return this.active; }

    // Begin the sequence. The Hero is grounded and in range (Enemy gates this).
    start() {
        const h = this.host;
        this._reset();
        this.active = true;
        this.facingLock = h.facing;
        this.startDir = h.facing;
        this.chaseDir = h.facing;
        this.pillarDir = h.facing;
        this.floorY = h.y + h.halfHeight;   // grounded at S1 -> exact floor surface
        this.markX = h.x; this.markY = h.y; // provisional; re-stored at W4 MARK
        this.farEndX = h.x;
        h.velocityX = 0;
        // publish frame 0 (drawn on the transition frame, before the first update tick)
        const e = TICK_MAP[0];
        this.frameName = e.clip; this.frameIndex = e.frame; this.tag = e.tag;
        this.drawTick = 0;
    }

    // The Enemy delegates its per-frame AI/physics to this while in COMBO_A. Each call
    // processes exactly one tick; the body frame and the world effects both key off the
    // JUST-processed tick (drawTick) so they can never drift by a frame, and completion
    // happens only AFTER the final SETTLE frame has been drawn.
    update(bossX = null) {
        // Boss centre x, kept fresh so the two directional snapshots below read the
        // CURRENT side. Nothing else in the combo consumes it — this is not tracking.
        if (bossX !== null && bossX !== undefined) this._bossX = bossX;
        // The clock runs at COMBO_A_TIME_SCALE, so each combo tick is held for
        // 1 / COMBO_A_TIME_SCALE game frames. Frame data, phase order and every
        // transition point are read from the SAME unchanged tick schedule.
        const t = Math.floor(this.clock);
        if (t >= TOTAL_TICKS) { this._complete(); return; }
        const h = this.host;

        this.drawTick = t;
        const e = TICK_MAP[t];
        this.frameName = e.clip; this.frameIndex = e.frame; this.tag = e.tag;

        const newTick = t !== this._lastTick;
        this._lastTick = t;
        if (newTick && e.first) this._enter(e.tag);
        // Publish the committed direction AFTER _enter, because W4 (chase start) and
        // P5A (pillar start) are the two transitions allowed to RE-POINT facingLock at
        // the Boss. Publishing before them left the body mirrored the old way for one
        // frame while that phase's world effects already used the new direction, so the
        // sprite visibly snapped a frame late. Everything else here (the strikes, the
        // advance, the grids) already reads facingLock directly, so only the sprite
        // mirror was affected — the committed/baitable direction itself is unchanged.
        h.facing = this.facingLock;
        this._continuous(e.tag);

        this.clock += COMBO_A_TIME_SCALE;
    }

    // Frame descriptor consumed by Enemy._animState (index-driven, like the combo).
    animFrame() { return { name: this.frameName, hold: 1, index: this.frameIndex }; }

    // --- transitions on the first tick of a frame ---
    _enter(tag) {
        const h = this.host;
        switch (tag) {
            case 'A1B': this._armStrike(STRIKES.A1B); break;        // S1 opener connects
            case 'J2':                                              // launch into the DIAGONAL dive
                this._gravOverride(true);
                this._airTick = 0;
                h.isGrounded = false;
                h.velocityY = 0; h.velocityX = 0;
                // C2: fix the diagonal landing target NOW (arena-clamped, ahead of launch).
                // Fixed at launch so the descent never re-homes on a moving Boss.
                this._diveLaunchX = h.x;
                this._diveTargetX = this._clampX(h.x + this.facingLock * DIVE_FORWARD_PX);
                break;
            case 'D2B':                                             // planted slam — landed AHEAD
                this._gravOverride(false);
                h.x = this._diveTargetX;                            // C2: land on the diagonal, ahead of launch
                h.y = this.floorY - h.halfHeight;
                h.velocityY = 0; h.velocityX = 0;
                h.isGrounded = true;
                this._armStrike(STRIKES.D2B);
                break;
            case 'A3B': this._spawnGlaive(); break;                 // the light leaves the sword
            case 'W4':                                              // SET THE MARK (return anchor)
                this.markX = h.x; this.markY = h.y;                 // return position — direction-independent
                // FOLLOW-UP fix 1: ONE directional decision as the chase step opens. If
                // the Boss crossed behind during the plunge, the cut goes the other way;
                // otherwise nothing changes. Re-pointing facingLock carries it to the
                // body facing, the A4B strike and the advance velocity in one place.
                this.chaseDir = this._bossDir(this.chaseDir);
                this.facingLock = this.chaseDir;
                break;
            case 'A4B': this._armStrike(STRIKES.A4B); break;        // the chase cut
            case 'P5A':                                             // seed the FORWARD CHAIN at the far end
                this.farEndX = h.x;
                this.floorY = h.y + h.halfHeight;                   // grounded — refresh floor
                // FOLLOW-UP fix 2: the chain always marches toward the Boss. ONE decision,
                // taken here as the pillar phase seeds — never re-taken per station beat.
                // Must precede _clampPillarAnchor(), which spans the chain by facing.
                this.pillarDir = this._bossDir(this.pillarDir);
                this.facingLock = this.pillarDir;
                // C3: anchor the near station on the far-end spot, then slide the whole
                // chain inward if it would overrun a wall (fixed per-station world spots).
                this.pillarAnchorX = this._clampPillarAnchor(h.x);
                h.velocityX = 0;
                break;
            case 'E5B':                                             // TELEPORT: warp back to THE MARK
                h.x = this.markX;
                h.y = this.markY;
                h.velocityX = 0; h.velocityY = 0;
                h.isGrounded = true;
                this._teleported = true;
                break;
            default: break;
        }
    }

    // --- continuous behaviour while a frame is held ---
    _continuous(tag) {
        const h = this.host;
        if (AIRBORNE_TAGS[tag]) {
            // Parametric DIAGONAL dive arc synced to the frame schedule (S2 only). Direct
            // x/y with gravity overridden to 0, so the post-update integration is inert
            // and the visual apex/turn/slam land on their approved frames. The +1 offset
            // keeps the Hero airborne for the WHOLE window (J2/T2/D2A) — launching off the
            // floor at once, apex mid-T2 — with only the D2B SLAM planting it.
            const p = (this._airTick + 1) / (AIRBORNE_TICKS + 1); // 0..1 across the airborne window
            const height = APEX_H * Math.sin(Math.PI * p);
            h.y = this.floorY - h.halfHeight - height;
            // C2 DIAGONAL: forward drift is ~0 through launch/apex, then ramps in over the
            // DESCENDING half so the hero cuts down-AND-forward and lands on _diveTargetX.
            // Direct-x (velocityX=0) toward a target fixed at launch -> stable, not homing;
            // main.js clampToWorld() remains the hard in-bounds backstop.
            const descent = Math.max(0, (p - 0.5) / 0.5);           // 0 at apex -> 1 at the plunge floor
            h.x = this._diveLaunchX + (this._diveTargetX - this._diveLaunchX) * descent;
            h.velocityX = 0; h.velocityY = 0;
            // fractional at half speed: the arc spans the same AIRBORNE_TICKS combo
            // ticks (now 24 game frames) — identical path, half the rate.
            this._airTick += COMBO_A_TIME_SCALE;
        } else if (ADVANCE_TAGS[tag] && !this._teleported) {
            // The controlled forward chase (~5 hero lengths). velocityX so main.js
            // clampToWorld() naturally stops it at either wall. Scaled by the playback
            // rate: twice as many frames at half the per-frame step -> SAME distance.
            h.velocityX = this.facingLock * ADVANCE_PER_TICK * COMBO_A_TIME_SCALE;
        } else {
            h.velocityX = 0;                                        // grounded, planted
        }
    }

    // STAGE 8C-4 FOLLOW-UP — which side is the Boss on RIGHT NOW? Returns +1/-1, or
    // `fallback` when the Boss is unknown or perfectly level with the Hero (no crossing
    // to detect -> keep the direction we already had, so nothing jitters). Called at
    // exactly two transitions; never per frame, never per pillar beat.
    _bossDir(fallback) {
        if (this._bossX === null) return fallback;
        return Math.sign(this._bossX - this.host.x) || fallback;
    }

    // --- the shared attackHitbox, configured per Combo-A strike (existing convention) ---
    _armStrike(cfg) {
        const h = this.host;
        h.attackHitbox.configure({
            reach: h.radius + cfg.reachOff,
            width: cfg.width,
            height: cfg.height,
            // active window is authored in COMBO TICKS -> game frames at the local rate,
            // so the strike still covers the same slice of its (slowed) frame
            duration: Math.round(cfg.active / COMBO_A_TIME_SCALE),
            damage: Math.max(1, Math.round(h.attackDamage * cfg.dmgMult)),
            knockback: cfg.knockback,
            velocityX: 0,
            velocityY: 0,
        });
        h.attackHitbox.kind = null;
        h.attackHitbox.trigger(true);
        h.attackHitbox.reposition(h.x, h.y, this.facingLock);
    }

    // --- the S3 slash projectile ---
    _spawnGlaive() {
        if (this._glaiveSpawned) return;
        this._glaiveSpawned = true;
        const h = this.host;
        const dir = this.facingLock;
        const hb = new Hitbox({
            reach: 0,
            width: GLAIVE.WIDTH,
            height: GLAIVE.HEIGHT,
            duration: Math.round(GLAIVE.LIFETIME / COMBO_A_TIME_SCALE),
            cooldown: 0,
            damage: Math.max(1, Math.round(h.attackDamage * GLAIVE.DMG_MULT)),
            knockback: GLAIVE.KNOCKBACK,
            velocityX: dir * GLAIVE.SPEED * COMBO_A_TIME_SCALE, // same travel path, half rate
            velocityY: 0,
            kind: GLAIVE.KIND,
        });
        hb.x = h.x + dir * (h.radius + GLAIVE.SPAWN_OFF);
        hb.y = h.y - GLAIVE.SPAWN_RISE;                            // off the blade tip
        hb.trigger(true);
        h.projectiles.push(hb);
    }

    _gravOverride(on) {
        const h = this.host;
        if (on && !this._gravityOverridden) {
            this._savedGravity = h.gravity;
            h.gravity = 0;
            this._gravityOverridden = true;
        } else if (!on && this._gravityOverridden) {
            h.gravity = this._savedGravity;
            this._gravityOverridden = false;
        }
    }

    // ---------------------------------------------------------------------
    // World-space effects (pure LIGHT grids). Painted at the same seam
    // drawWaveProjectiles uses (behind the body). Frames derive from the master
    // tick / pillar clock so they can never desync from the body.
    // ---------------------------------------------------------------------
    drawWorldEffects(ctx) {
        if (!this.active) return;
        const t = this.drawTick;            // the just-processed tick — stays in lock-step with the body frame
        // FOLLOW-UP: each world effect mirrors off the direction OF ITS OWN PHASE, not
        // off the live facingLock. Same art, same anchors — this only stops an effect
        // that is already on screen from mirroring under it when a later phase flips.
        const glaiveFlip = this.startDir === -1;
        const corridorFlip = this.chaseDir === -1;
        const pillarFlip = this.pillarDir === -1;

        // Corridor — the cut path + fading residue bed the return lands in.
        // CR0 cut [57,69) · CR1 lit-bed [69,89) (the return at 88 lands here) · CR2 residue [89,97).
        if (t >= CORRIDOR_START && t < TOTAL_TICKS) {
            const cf = t < PILLAR_START ? 0 : (t < CORRIDOR_LIT_END ? 1 : 2);
            this._paint(ctx, LIGHT_GRIDS.lightCorridor[cf], G_CORRIDOR.cx, G_CORRIDOR.row,
                this.markX, this.markY - RETURN_BED_DY, corridorFlip);
        }

        // Pillar CHAIN (C3) — the forward sequential column burst, pinned to the floor.
        // The near station (G_PILLAR.cx) sits on the arena-clamped anchor; the chain is
        // DIRECTIONAL, so it mirrors with facing to march FORWARD in the attack direction.
        const pf = frameFromClock(t - PILLAR_START, PILLAR_CLOCK);
        if (pf >= 0) {
            this._paint(ctx, LIGHT_GRIDS.lightPillar[pf], G_PILLAR.cx, G_PILLAR.baseRow,
                this.pillarAnchorX, this.floorY, pillarFlip); // directional chain — mirrors toward the Boss
        }

        // Reform — the arrival snap AT THE MARK, inside the still-lit bed.
        if (t >= REFORM_START && t < TOTAL_TICKS) {
            const rf = t < ARRIVE_TICK ? 0 : (t < ARRIVE_TICK + 2 ? 1 : 2);
            this._paint(ctx, LIGHT_GRIDS.lightReform[rf], G_REFORM.cx, G_REFORM.cy,
                this.markX, this.markY - RETURN_BED_DY, false); // h-symmetric
        }

        // Glaive — the thrown slash projectile (Combo-A-owned, in host.projectiles).
        const glaive = this.host.projectiles
            && this.host.projectiles.find((p) => p.kind === GLAIVE.KIND && p.isActive);
        if (glaive) {
            const lp = glaive.lifeProgress || 0;
            let gf;
            if (lp < 0.15) gf = 0;                                 // GL0 birth
            else if (isLiteVfx()) gf = 1;                          // lite/perf: steady travel (no shimmer)
            else gf = (Math.floor(t / 3) % 2) ? 2 : 1;             // GL1 <-> GL2 shimmer loop
            this._paint(ctx, LIGHT_GRIDS.lightGlaive[gf], G_GLAIVE.cx, G_GLAIVE.cy,
                glaive.x, glaive.y, glaiveFlip);
        }
    }

    // Paint a pure-LIGHT grid so its (cx,cy) cell lands on (worldCX,worldCY), at the
    // hero 2px grid, mirrored under a facing flip.
    _paint(ctx, matrix, cx, cy, worldCX, worldCY, flip) {
        if (!matrix || !matrix.length) return;
        const PX = HERO_IDLE_PIXEL;
        const cols = matrix[0].length;
        const effCx = flip ? (cols - 1 - cx) : cx;
        const ox = Math.round(worldCX - effCx * PX);
        const oy = Math.round(worldCY - cy * PX);
        SpriteManager.drawMatrix(ctx, matrix, ox, oy, PX, { palette: HERO_REDESIGN_PALETTE, flip });
    }

    // Arena clamp for the hero's own x (the diagonal-plunge landing target). main.js
    // clampToWorld() is the hard per-frame backstop; this just keeps the FIXED dive
    // target in-bounds so the landing reads cleanly. host.worldWidth is set by main.js.
    _clampX(x) {
        const h = this.host;
        const max = (h.worldWidth || Infinity) - h.halfWidth;
        return Math.max(h.halfWidth, Math.min(max, x));
    }

    // C3 arena clamp for the FORWARD pillar chain. The chain is a render-only world
    // effect (no clampToWorld backstop), so if it would overrun a wall we slide the
    // whole anchor inward — preserving the fixed per-station spacing (never compressing
    // stations together, never leaving the arena). The near station sits G_PILLAR.cx
    // cells behind the anchor; the chain reaches forward to the grid's far column.
    _clampPillarAnchor(anchorX) {
        const worldMax = this.host.worldWidth || Infinity;
        const PX = HERO_IDLE_PIXEL;
        const back = G_PILLAR.cx * PX;                       // cells behind the near station
        const fwd = (PILLAR_COLS - 1 - G_PILLAR.cx) * PX;    // cells ahead to the far edge
        const dir = this.facingLock;
        let left = dir > 0 ? anchorX - back : anchorX - fwd; // world span of the chain for this facing
        let right = dir > 0 ? anchorX + fwd : anchorX + back;
        if (left < 0) anchorX += -left;                      // slid off the left wall -> push right
        if (right > worldMax) anchorX -= (right - worldMax); // slid off the right wall -> push left
        return anchorX;
    }

    // ---------------------------------------------------------------------
    // Lifecycle end. cleanup() is idempotent: safe to call repeatedly / after an
    // interrupt / on death / on reset without creating new errors or effects.
    // ---------------------------------------------------------------------
    _complete() {
        const h = this.host;
        this.cleanup();                    // active -> false; Enemy sees this and exits COMBO_A
        h._comboACooldown = COMBO_A_COOLDOWN;
        h._repositionAfterAttack = true;   // peel away, like every other attack
    }

    cleanup() {
        const h = this.host;
        // restore the local vertical override / diagonal-plunge gravity (never leak gravity=0)
        this._gravOverride(false);
        // remove any Combo-A-owned projectile still in flight
        if (h.projectiles && h.projectiles.length) {
            h.projectiles = h.projectiles.filter((p) => p.kind !== GLAIVE.KIND);
        }
        // close any live strike window this combo opened
        if (h.attackHitbox) h.attackHitbox.activeTimer = 0;
        // Drop the chase MOVEMENT OVERRIDE. On normal completion the last tick already
        // parked it, but an interrupt can land mid-chase (A4A/A4B/L4) while velocityX
        // still carries the advance step; the paths that re-drive it immediately
        // (takeDamage / triggerFear) set their own velocity AFTER this, while the ones
        // that only damp it (the intimidation break -> _waryStep) would otherwise slide
        // the Hero on for ~187px. Same guarantee HeroDragonWrath.cleanup() already gives.
        h.velocityX = 0;
        this.active = false;
        this._teleported = false;
        // drop the C2 diagonal-plunge / C3 chain override state (idempotent; also
        // re-initialised by start()->_reset(), so a stale value can never carry over)
        this._airTick = 0;
        this._diveTargetX = 0;
        this._diveLaunchX = 0;
    }
}

// Selection tuning — how often Combo A stands in for the 4-hit combo, and the gate
// after one runs. Local to the Hero attack system; kept small so Combo A stays an
// occasional variant that never dominates Hero behaviour.
export const COMBO_A_SELECT_CHANCE = 0.35;  // per eligible melee-start
export const COMBO_A_COOLDOWN = 300;        // ~5s @60fps before it can be picked again
